      values[index] = constrainValue(dateValue, min, max);
      send({ type: "VALUE.SET", value: values });
    },
    clearValue(options = {}) {
      const { focus = true } = options;
      send({ type: "VALUE.CLEAR", focus });
    },
    setFocusedValue(value) {
      send({ type: "FOCUS.SET", value });
    },
